import{_ as t,r as p,o,c as i,a as n,b as s,d as e,e as c}from"./app-52052bff.js";const l="/assets/image-d82e03c1.png",r="/assets/image2-0f06aa2e.png",u={},d=n("h2",{id:"实验准备",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#实验准备","aria-hidden":"true"},"#"),s(" 实验准备")],-1),k={href:"http://nil.csail.mit.edu/6.824/2020/papers/mapreduce.pdf",target:"_blank",rel:"noopener noreferrer"},m={href:"http://nil.csail.mit.edu/6.824/2020/labs/lab-mr.html",target:"_blank",rel:"noopener noreferrer"},v=c('<h2 id="任务分析" tabindex="-1"><a class="header-anchor" href="#任务分析" aria-hidden="true">#</a> 任务分析</h2><p>需要在 <code>mr/master.go</code>、<code>mr/worker.go</code> 和 <code>mr/rpc.go</code> 中实现以下功能</p><ul><li>Master 负责 Map/Reduce 任务的调度 <ul><li>Master 响应 Worker 的请求</li><li>统计 Map/Reduce 任务的完成情况</li><li>记录 Worker 状态，如果 Worker 下线或者处理任务的时间较长，需要将该 Worker 处理的任务交给其他 Worker 处理</li></ul></li><li>Worker 负责处理 Map/Reduce 任务 <ul><li>空闲时向 Master 请求任务，任务处理完成之后通知 Master</li><li>如果 Worker 在规定的时间内没有完成任务，Master 需要将任务交给其他 Worker</li></ul></li><li>Master 和 Worker 通过 RPC 通信</li><li>Map 任务需要将不同的 Key(文本中的单词) 映射到不同的文件中，文件的格式为 <code>mr-X-Y</code>, X 是映射编号，Y 是文本编号</li><li>Reduce 任务需要将映射编号为 X 的文件中的内容进行排序并保存到 <code>mr-out-X</code> 文件中</li><li>在任务全部完成后，退出程序</li></ul><p><img src="'+l+`" alt="Alt text"></p><h2 id="设计实现" tabindex="-1"><a class="header-anchor" href="#设计实现" aria-hidden="true">#</a> 设计实现</h2><h3 id="master-设计" tabindex="-1"><a class="header-anchor" href="#master-设计" aria-hidden="true">#</a> Master 设计</h3><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">type</span> Master <span class="token keyword">struct</span> <span class="token punctuation">{</span>
	Workers      <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token operator">*</span>WorkerInfo <span class="token comment">// Worker 信息</span>
	MapTask      <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">int64</span><span class="token punctuation">]</span><span class="token operator">*</span>Task        <span class="token comment">// 保存所有的Map任务信息</span>
	ReduceTask   <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">int64</span><span class="token punctuation">]</span><span class="token operator">*</span>Task        <span class="token comment">// 保存所有的Reduce任务信息</span>
	TaskChan     <span class="token keyword">chan</span> Task              <span class="token comment">// 任务管道</span>
	Status       <span class="token builtin">int</span>                    <span class="token comment">// Master 状态</span>
	ComplMaps    <span class="token builtin">int</span>                    <span class="token comment">// 完成的 Map 任务</span>
	ComplReduces <span class="token builtin">int</span>                    <span class="token comment">// 完成的 Reduce 任务</span>
	NReduce      <span class="token builtin">int</span>
	lock         sync<span class="token punctuation">.</span>Mutex
<span class="token punctuation">}</span>

<span class="token keyword">type</span> Task <span class="token keyword">struct</span> <span class="token punctuation">{</span>
	TaskId     <span class="token builtin">int64</span>    <span class="token comment">// 任务ID,时间戳</span>
	TaskType   <span class="token builtin">int</span>      <span class="token comment">// 0: Map   1: Reduce</span>
	TaskStatus <span class="token builtin">int</span>      <span class="token comment">// 0: 进行中  1：已完成  -1:未开始</span>
	InputFile  <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span> <span class="token comment">// 输入文件</span>
	OutputFile <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span> <span class="token comment">// 输出文件</span>
	NReduce    <span class="token builtin">int</span>

	WorkerAddr <span class="token builtin">string</span>    <span class="token comment">// 处理该任务的 Worker 地址</span>
	StartTime  time<span class="token punctuation">.</span>Time <span class="token comment">// 开始处理时间</span>
<span class="token punctuation">}</span>

<span class="token comment">// Worker 获取任务 </span>
<span class="token keyword">func</span> <span class="token punctuation">(</span>m <span class="token operator">*</span>Master<span class="token punctuation">)</span> <span class="token function">GetTaskOrSendWorkinfo</span><span class="token punctuation">(</span>workerInfo WorkerInfo<span class="token punctuation">,</span> reply <span class="token operator">*</span>WorkerInfo<span class="token punctuation">)</span> <span class="token builtin">error</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// Worker 返回处理结果</span>
<span class="token keyword">func</span> <span class="token punctuation">(</span>m <span class="token operator">*</span>Master<span class="token punctuation">)</span> <span class="token function">ReturnTaskRes</span><span class="token punctuation">(</span>workerInfo WorkerInfo<span class="token punctuation">,</span> reply <span class="token operator">*</span>WorkerInfo<span class="token punctuation">)</span> <span class="token builtin">error</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// 监听 Master 状态</span>
<span class="token keyword">func</span> <span class="token punctuation">(</span>m <span class="token operator">*</span>Master<span class="token punctuation">)</span> <span class="token function">listenTask</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token keyword">func</span> <span class="token punctuation">(</span>m <span class="token operator">*</span>Master<span class="token punctuation">)</span> <span class="token function">Done</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">bool</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// ........</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>解释四个主要方法是需要完成的任务：</p><ul><li><code>GetTaskOrSendWorkinfo</code>: Master 需要存储 Worker 信息，来处理超时的情况， 因此 Worker 需要向 Master 请求任务，并定时发送 Worker 的状态信息。当Worker 处于空闲状态，Master 会分配 Map/Reduce 任务给 Worker，并更新 Worker 信息</li><li><code>ReturnTaskRes</code>: 当 Worker 完成 Map/Reduce 任务，返回处理结果给 Master，如果当前 Master 还有任务，分配一个任务给改 Worker，减少一次网络请求</li><li><code>listenTask</code>: 监听 Master 状态，如果正在处理 Map 任务，那么 Master 会遍历所有的 Map 任务，将 10s 内没有完成的任务交给其他空闲 Worker。</li><li><code>Done</code>: 当所有任务都结束，结束程序</li></ul><h3 id="worker-设计" tabindex="-1"><a class="header-anchor" href="#worker-设计" aria-hidden="true">#</a> Worker 设计</h3><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// 处理 Map 任务</span>
<span class="token keyword">func</span> <span class="token function">processMapTask</span><span class="token punctuation">(</span>worker <span class="token operator">*</span>WorkerInfo<span class="token punctuation">,</span> mapf <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token builtin">string</span><span class="token punctuation">,</span> <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>KeyValue<span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// 处理 Reduce 任务</span>
<span class="token keyword">func</span> <span class="token function">processReduceTask</span><span class="token punctuation">(</span>worker <span class="token operator">*</span>WorkerInfo<span class="token punctuation">,</span> reducef <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token builtin">string</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// ..........</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Worker 的设计比较简单，主要是上面两个函数，分别处理 Map 和 Reduce 任务</p><h3 id="rpc-设计" tabindex="-1"><a class="header-anchor" href="#rpc-设计" aria-hidden="true">#</a> RPC 设计</h3><p>Master 和 Worker 通过 RPC 通信</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">type</span> TaskInfo <span class="token keyword">struct</span> <span class="token punctuation">{</span>
	TaskId     <span class="token builtin">int64</span>    <span class="token comment">// 任务ID</span>
	TaskType   <span class="token builtin">int</span>      <span class="token comment">// 0: Map   1: Reduce</span>
	TaskStatus <span class="token builtin">int</span>      <span class="token comment">// 0: 进行中  1：已完成  -1:未开始</span>
	InputFile  <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span> <span class="token comment">// 输入文件</span>
	OutputFile <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span> <span class="token comment">// 输出文件</span>
	NReduce    <span class="token builtin">int</span>
<span class="token punctuation">}</span>

<span class="token keyword">type</span> WorkerInfo <span class="token keyword">struct</span> <span class="token punctuation">{</span>
	WorkerAddr  <span class="token builtin">string</span>
	Status      <span class="token builtin">int</span>       <span class="token comment">// 0: 空闲 1：处理任务 -1: 结束 worker 进程</span>
	TaskInfo    <span class="token operator">*</span>TaskInfo <span class="token comment">// 处理的任务的信息</span>
	LastReqTime time<span class="token punctuation">.</span>Time <span class="token comment">// 上一次发送请求的时间</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="测试" tabindex="-1"><a class="header-anchor" href="#测试" aria-hidden="true">#</a> 测试</h2><p>执行测试脚本：<code>bash test-mr.sh</code><img src="`+r+'" alt="Alt text"></p><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><ul><li>刚开始调试时比较麻烦，因为开始时是使用 <code>fmt.Printf</code> 直接打印到控制台中，后面使用 <code>log</code> 输出到对应的日志文件中</li><li>在设计 Master 时，由于对 <code>lock</code> 的使用不当，连续Lock多次，造成了死锁，调试的时候出现程序卡住，无法向下运行，对代码进行了梳理，调整了锁的使用和释放</li><li>在进行 <code>crash test</code> 时，调试了较长时间，因为会随机退出正在执行的Worker线程，Master 需要重新分发该 Worker 的任务，在这个过程中忽略了某些状态的修改（重置），导致任务一直被重写分发，导致死锁</li></ul>',19);function b(h,f){const a=p("ExternalLinkIcon");return o(),i("div",null,[d,n("ul",null,[n("li",null,[s("MapReduce 论文: "),n("a",k,[s("http://nil.csail.mit.edu/6.824/2020/papers/mapreduce.pdf"),e(a)])]),n("li",null,[s("Lab1 要求: "),n("a",m,[s("http://nil.csail.mit.edu/6.824/2020/labs/lab-mr.html"),e(a)])])]),v])}const M=t(u,[["render",b],["__file","lab1.html.vue"]]);export{M as default};
